var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`하하핫, 사장님! 호출했다면서?`,JPN:`はははっ、社長！　呼んだか？`,ENG:`Hah hah, Boss! Did you want to see me?`,TWN:`哈哈哈，老闆！聽說你叫我？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`마침 잘 불렀어. 그렇잖아도 방금 돈 냄새가 솔솔 나는 대박 건수를 잡았거든.`,JPN:`ちょうどよかった。金の匂いがプンプンするすげぇ案件をとってきたぜ。`,ENG:`You called me at the right time. I've just found out about a job that smells like money.`,TWN:`你可真是叫對人了，我剛剛才找到了一份可以大撈一票的差事。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`......엉? 종신 계약?`,JPN:`……はあ？　終身契約？`,ENG:`Huh? A lifetime contract?`,TWN:`......啊？終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`이거 참. 쓸 만한 보디가드가 필요했으면 진즉 말하지 그랬어.`,JPN:`まったく。使えそうなボディガードが必要だったら早く言えばよかったのに。`,ENG:`Man, if you needed an able bodyguard, why didn't you say so?`,TWN:`真是的，你要能幹的保鏢就早說啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`맡겨 둬. 우린 같이 대박을 터뜨리기로 약속한 사이잖아?`,JPN:`任せとけ。俺たちは大儲けしようって約束した仲だろう？`,ENG:`Count on me. We've promised to get rich together, right?`,TWN:`交給我吧。我們不是已經約好要一起賺大錢了嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`이상한 녀석들은 얼씬도 못하게 해 주지!`,JPN:`変な奴らが近づけないようにしてやるからな！`,ENG:`I'll make sure you're safe from all threats!`,TWN:`我不會讓那些奇怪的傢伙靠近你的！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`자, 빨랑 도장 찍고 노다지를 캐러 가자고! 으하하핫!!`,JPN:`さぁ、さっさとハンコを押して一儲けしに行こうぜ！
うはははっ！！`,ENG:`Come on, let's get this over with and go find a gold mine! Mwa hah hah!`,TWN:`來，快點蓋個章，我們去大賺一筆吧！哇哈哈哈！！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};